$(document).ready(function () {
    listenerCheckPrivacyAndTerms();

    $(document).on('click', 'a.edit-field', (e) => handlerEditFields(e));

    $("#pininput").keyup(function () {
        var self = this;
        var caretPos = self.selectionStart;
        var raw = self.value.replace(/[^a-zA-Z0-9]/g, '').substring(0, 32);

        if (raw.length <= 8) return;

        var formatted = raw.substring(0, 8)
            + '-' + raw.substring(8, 12)
            + (raw.length > 12 ? '-' + raw.substring(12, 16) : '')
            + (raw.length > 16 ? '-' + raw.substring(16, 20) : '')
            + (raw.length > 20 ? '-' + raw.substring(20, 32) : '');

        if (self.value === formatted) return;

        // Ajusta caret: conta quantos hifens foram inseridos antes da posição atual
        var charsBeforeCaret = self.value.substring(0, caretPos).replace(/-/g, '').length;
        self.value = formatted;

        // Recalcula posição do caret no valor formatado
        var newCaret = 0, count = 0;
        for (var i = 0; i < formatted.length; i++) {
            if (formatted[i] !== '-') count++;
            if (count === charsBeforeCaret) { newCaret = i + 1; break; }
        }

        setTimeout(function () {
            if (self.setSelectionRange) self.setSelectionRange(newCaret, newCaret);
        }, 0);
    });
});

function checkInputPinMask() {
    var val = $("#pininput").val() || "";
    if (val.length > 15)
        setPinHypeMask()
    else
        $("#pininput").unmask();
}

function setPinHypeMask() {
    $('.input-pin-code').mask('ZZZZZZZZ-ZZZZ-ZZZZ-ZZZZ-ZZZZZZZZZZZZ', {
        translation: {
            'Z': {
                pattern: /[a-zA-Z0-9]/
            }
        }
    });
}

function validateField(field, fieldName) {
    if (!field) {
        return vFail(getTranslation("RequiredFieldError", fieldName))
    }
    if (field.prop("required") && field.val() == "") {
        return vFail(getTranslation("RequiredFieldError", fieldName))
    }
    if (hasAttr(field, "maxlength") && field.val().length > field.attr("maxlength")) {
        return vFail(getTranslation("MaxLengthError", fieldName, field.attr("maxlength")))
    }
    if (hasAttr(field, "minlength") && field.val().length < field.attr("minlength")) {
        return vFail(getTranslation("MinLengthError", fieldName, field.attr("minlength")))
    }
    if (hasAttr(field, "pattern")) {
        var regex = new RegExp(field.attr("pattern"))
        if (fieldName == "PIN") {
            field.val(field.val().trim())
        }

        if (fieldName == "Data de Nascimento") {
            if (regex.test(field.val()) == false) {
                return vFail(getTranslation("InvalidBornAtError", fieldName))
            }
        }

        if (regex.test(field.val()) == false) {
            return vFail(getTranslation("InvalidFieldError", fieldName))
        }
    }
    return vSuccess();
}

